export function IcoNavControls() {
  const { palette } = useIlloStyle();
  // 3×2 control grid of arrow circles
  const cells = [
    { x: 44, y: 30, label: '↖' }, { x: 100, y: 30, label: '↑' }, { x: 156, y: 30, label: '↗' },
    { x: 44, y: 80, label: '←' }, { x: 100, y: 80, label: '↓' }, { x: 156, y: 80, label: '→' },
  ];
  return (
    <svg viewBox="0 0 200 130" preserveAspectRatio="xMidYMid slice" style={{ width: '100%', height: '100%' }}>
      <rect width="200" height="130" fill={palette.dark} />
      {cells.map(({ x, y, label }) => (
        <g key={`${x}-${y}`}>
          <circle cx={x} cy={y} r="18" fill={palette.mid} opacity="0.35" stroke={palette.mid} strokeWidth="2" />
          <text x={x} y={y + 6} textAnchor="middle" fontSize="16" fill={palette.accent} fontWeight="bold">{label}</text>
        </g>
      ))}
    </svg>
  );
}
